sql:
SELECT armor_name
FROM armor_types
WHERE defense_value > 10;

SELECT COUNT(character_id) AS character_count
FROM character_skills
WHERE skill_id = 1;

SELECT COUNT(*) AS equipped_count
FROM armor_inventory
WHERE equipped = 1 AND armor_id = 1;

SELECT COUNT(character_id)
FROM skill_progressions
WHERE skill_id = 1 AND level = 1;

SELECT armor_id
FROM armor_inventory
WHERE character_id = 0 AND equipped = 1;

external_knowledge:
; Rare armor refers to armor with a rarity of 'rare' in the armor_types table; 
; Equipped armor means armor with a value of 1 in the equipped column of the armor_inventory table; 
; Class type refers to the class_type column in the characters table.

sql:
SELECT session_id, session_duration
FROM sessions
ORDER BY session_duration DESC;

SELECT COUNT(character_id)
FROM character_skills
WHERE skill_id = (SELECT skill_id FROM skills WHERE skill_name = 'Pick Pocket');

external_knowledge:
; A skill is considered 'usable' if its next use time is on or before the current time ('2023-02-01T10:10:00Z' in this case);
; Meeting the 'minimum level requirement for the skill' means the character's level is greater than or equal to the skill's 'learnable_at_level';
; 'Associated armor' refers to armor that affects the skill's current effect and is currently equipped by the character.
